searchBook.requestInfo:
@js:
var cat = 'xuanhuan';
if (params && params.filters && params.filters.category) {
  cat = String(params.filters.category);
}
var page = parseInt(params.pageIndex || 1, 10);
if (!page || page < 1) page = 1;
var host = String(config.host || 'https://www.novel543.com').replace(/\/$/, '');
var url = host + '/bookstack/' + cat + '/';
if (page > 1) url = host + '/bookstack/' + cat + '/?page=' + page;
return {'url': url, 'httpHeaders': config.httpHeaders};

searchBook.nextPageUrl:
//ul[contains(@class,'pagination-list')]//a[contains(@class,'pagination-link') and not(contains(@class,'disabled'))][last()]/@href||@js:
var cand = String(result || '').trim();
if (!cand) return '';
var cur = String(params.responseUrl || '');
var m1 = cur.match(/page=(\d+)/);
var m2 = cand.match(/page=(\d+)/);
var curPage = parseInt(m1 ? m1[1] : '1', 10);
var nextPage = parseInt(m2 ? m2[1] : '1', 10);
if (!nextPage || nextPage <= curPage) return '';
return cand;

bookDetail.requestInfo:
