  if (params.queryInfo.detailUrl) return params.queryInfo.detailUrl;
  if (params.queryInfo.url) return params.queryInfo.url;
}
if (typeof result === 'string') return result;
if (result && result.detailUrl) return result.detailUrl;
if (result && result.url) return result.url;
