chapterList.requestInfo:
@js:
var host = String(config.host || 'https://www.novel543.com').replace(/\/$/, '');
var u = '';
if (params && params.queryInfo) u = params.queryInfo.url || params.queryInfo.detailUrl || '';
if (!u && typeof result === 'string') u = result;
if (!u && result && result.url) u = result.url;
if (!u && result && result.detailUrl) u = result.detailUrl;
if (!u && params && params.responseUrl) u = params.responseUrl;
u = String(u).trim().split(/\s+/)[0] || '';
if (u.indexOf('/dir') < 0) {
  var m = u.match(/\/(\d{8,})\/?/);
  if (m) u = host + '/' + m[1] + '/dir';
}
if (u && u.indexOf('http') !== 0) u = host + u;
return {'url': u, 'httpHeaders': config.httpHeaders};

chapterList.title:
//text()||@js:
var t = String(result || '').replace(/\s+/g, ' ').trim();
var m = t.match(/第\d+章[^第]*/);
if (m) return m[0].trim();
if (t.length < 80) return t;
return t;

chapterList.url:
//@href||@js:
var parts = String(result || '').trim().split(/\s+/);
if (parts.length === 1) return parts[0];
var hit = parts.find(function(x){return /\/\d{8,}\/\d+_\d+\.html/.test(x);});
return hit || parts[0] || '';

chapterList.detailUrl:
//@href||@js:
