chapterContent.requestInfo:
@js:
var host = String(config.host || 'https://www.novel543.com').replace(/\/$/, '');
function parseChapter(u) {
  var m = String(u || '').match(/\/(\d{8,})\/(\d+)_([0-9]+)(?:_([0-9]+))?\.html/i);
  if (!m) return null;
  return {bookId: m[1], sid: m[2], cid: parseInt(m[3], 10), sub: parseInt(m[4] || '1', 10)};
}
var qi = '';
if (params && params.queryInfo) qi = params.queryInfo.url || params.queryInfo.detailUrl || '';
var u = String(qi).trim().split(/\s+/)[0] || '';
var np = params && params.lastResponse ? String(params.lastResponse.nextPageUrl || '').trim().split(/\s+/)[0] : '';
if (np && u) {
  var a = parseChapter(np), b = parseChapter(u);
  if (a && b && a.bookId === b.bookId && a.sid === b.sid && a.cid === b.cid && a.sub > b.sub) u = np;
} else if (!u && np) {
  u = np;
}
if (!u && result) {
  if (typeof result === 'string') u = result;
  else if (result.url) u = result.url;
  else if (result.detailUrl) u = result.detailUrl;
}
if (!u && params && params.responseUrl) u = params.responseUrl;
u = String(u).trim().split(/\s+/)[0] || '';
var detail = '';
if (params && params.queryInfo) detail = params.queryInfo.detailUrl || params.queryInfo.url || '';
var bm = String(detail).match(/\/(\d{8,})\//);
var bookId = bm ? bm[1] : '';
var um = parseChapter(u);
if (bookId && um && um.bookId !== bookId) {
  u = '/' + bookId + '/' + um.sid + '_' + um.cid + (um.sub > 1 ? '_' + um.sub : '') + '.html';
}
if (u && u.indexOf('http') !== 0) u = host + u;
var hh = config.httpHeaders || {};
var headers = {'User-Agent': hh['User-Agent'] || '', 'Accept': hh['Accept'] || '', 'Accept-Language': hh['Accept-Language'] || ''};
if (bookId) headers.Referer = host + '/' + bookId + '/';
else if (u) headers.Referer = u;
return {'url': u, 'httpHeaders': headers};

chapterContent.content:
//div[@id='chapterWarp']//div[contains(@class,'py-5')]||@js:
var html = String(result || '');
if (!html) return '';
html = html.replace(/<div[^>]*class="[^"]*(?:gadBlock|adBlock)[^"]*"[^>]*>[\s\S]*?<\/div>/gi, '');
html = html.replace(/<div[^>]*style="[^"]*height:\s*100px[^"]*"[\s\S]*?<\/div>/gi, '');
html = html.replace(/<script[\s\S]*?<\/script>/gi, '');
html = html.replace(/<ad[^>]*>[\s\S]*?<\/ad>/gi, '');
var text = html.replace(/<br\s*\/?>/gi, '\n').replace(/<\/p>/gi, '\n').replace(/<[^>]+>/g, '').replace(/溫馨提示[\s\S]*$/g, '').replace(/\n{2,}/g, '\n').trim();
if (/章節錯誤|章节错误/.test(text) && text.length < 120) return '';
return text;

chapterContent.nextPageUrl:
//div[contains(@class,'foot-nav')]//a/@href||@js:
var cur = String(params.responseUrl || '');
function parse(u) {
  var m = String(u || '').match(/\/(\d{8,})\/(\d+)_([0-9]+)(?:_([0-9]+))?\.html/i);
  if (!m) return null;
  return {bookId: m[1], sid: m[2], cid: parseInt(m[3], 10), sub: parseInt(m[4] || '1', 10)};
}
var c1 = parse(cur);
if (!c1) return '';
var parts = String(result || '').trim().split(/\s+/);
for (var i = 0; i < parts.length; i++) {
  var c2 = parse(parts[i]);
  if (!c2) continue;
  if (c1.bookId === c2.bookId && c1.sid === c2.sid && c1.cid === c2.cid && c2.sub > c1.sub) return parts[i];
}
return '';

